      "input": {
        "action": "delete_platform",
        "platform_id": 1
      },
      "output": {
        "status": "success",
        "message": "Platform deleted successfully"
      },
      "notes": "Validates deleting an existing platform."
    },
    {
      "name": "user_panel_asset_upload_valid",
      "input": {
        "action": "upload_asset",
