        "asset": {
          "file_name": "image.jpg",
          "format": "Feed"
        }
      },
      "output": {
        "status": "success",
        "message": "Asset uploaded successfully"
      },
      "notes": "Validates successful asset upload by a user."
    },
    {
      "name": "user_panel_asset_upload_invalid_format",
