          "platform_id": 1,
          "cropping_logic": "face-centric",
          "overlay_zones": ["logo", "text-safe"]
        }
      },
      "output": {
        "status": "success",
        "message": "Template rule added successfully"
      },
      "notes": "Validates adding a new image template rule."
    },
    {
      "name": "admin_panel_ai_behavior_controls_update",
      "input": {
        "action": "update_ai_behavior",
        "settings": {
          "enable_manual_editing": true,
          "adaptation_strategy": "crop"
        }
      },
      "output": {
        "status": "success",
        "message": "AI behavior updated successfully"
      },
      "notes": "Validates updating AI behavior controls."
    },
    {
      "name": "user_panel_asset_generation_invalid_user",
      "input": {
        "action": "generate_asset",
        "user_id": 999,
        "asset_id": 1
      },
      "output": {
        "status": "error",
        "message": "User not found"
      },
      "notes": "Tests edge case of generating an asset with an invalid user ID."
    },
